    public static readonly CapabilityMatrix S3 = new(
        ServiceName: "s3",
        Operations: new OperationCapability[]
        {
            new("AbortMultipartUpload", OperationStatus.Implemented, new[] { "Azure: (no-op; uncommitted blocks GC after 7 days)", "Diff: Server-side no-op once the UploadId is validated. Azure auto-removes uncommitted blocks ~7 days after their last upload, which matches the UploadId TTL — so an aborted upload's blocks expire on the same schedule as a forgotten one.", "Diff: The destination bucket is still probed so a missing container surfaces NoSuchBucket instead of 204.", "Diff: Subsequent UploadPart calls on the same UploadId continue to succeed until the TTL expires (no active invalidation). To prevent reuse, callers should treat the UploadId as discarded after Abort." }),
            new("CompleteMultipartUpload", OperationStatus.Implemented, new[] { "Azure: Put Block List", "Diff: Response ETag has the S3 multipart shape \"{hash}-{count}\" but {hash} is derived from the Azure blob ETag (no per-part MD5s are retained). SDKs that only pattern-match the dash-suffix accept it as multipart.", "Diff: Missing/unknown PartNumbers surface as InvalidPart (mapped from Azure's InvalidBlockList).", "Diff: Request body cap of 4 MiB (>10× the worst-case 10,000-part payload).", "Diff: Client-supplied per-part <ETag> values are not validated. Blocks are addressed by (uploadId.nonce, PartNumber) only — if the same PartNumber was UploadPart'd twice with different bytes, Complete will commit the latest version regardless of which ETag the client sends. S3 would reject the stale ETag with InvalidPart. Workflows that don't overwrite parts within an upload are unaffected.", "Diff: S3's minimum part size (5 MiB for all but the final part) is NOT enforced. aws2azure commits the supplied block list without size validation; S3 would otherwise reject with EntityTooSmall. The Azure block-size ceiling (~4000 MiB per block, 190.7 TiB per blob) still applies." }),
            new("CopyObject", OperationStatus.Implemented, new[] { "Azure: PUT https://{account}.blob.core.windows.net/{container}/{blob} with x-ms-copy-source", "Diff: Intra-account copies are synchronous on Azure; the proxy verifies x-ms-copy-status=success before responding 200.", "Diff: ETag in CopyObjectResult is normalised to the same S3-shaped, proxy-translated value HEAD/GET emit for the destination blob (synthetic MD5 of Azure's raw ETag when Content-MD5 is absent), so clients can reuse it across operations without seeing two different ETags for the same object." }),
            new("CreateBucket", OperationStatus.Implemented, new[] { "Azure: PUT https://{account}.blob.core.windows.net/{container}?restype=container", "Diff: Bucket name == container name; Azure container naming is stricter than S3 (3–63 lowercase, digits, single hyphens, no leading/trailing hyphen).", "Diff: Location response header is host-relative ('/{bucket}') since the proxy doesn't know its public hostname.", "Diff: Region-sensitive idempotency is reproduced from the signed credential scope: in us-east-1 re-creating a bucket you already own returns 200 OK (idempotent), matching real S3; other regions return 409 BucketAlreadyOwnedByYou. Azure's ContainerAlreadyExists drives this; Azure does not expose 'owned by someone else' separately, so BucketAlreadyExists (foreign owner) cannot be distinguished and is always treated as owned-by-you.", "Diff: BucketAlreadyOwnedByYou error envelopes omit the informational <BucketName> element real S3 includes. [conformance:bucketalreadyownedbyyou-recreate::missing-field:BucketName]" }),
            new("CreateMultipartUpload", OperationStatus.Implemented, new[] { "Azure: Stateless UploadId (no Azure call until UploadPart)", "Diff: UploadId is a 32-byte stateless token (base64url, 43 chars) HMAC-bound to (account, container, key) using the Azure account key. No Azure call is made on initiate.", "Diff: UploadIds expire after 7 days, matching Azure's uncommitted-block GC window. Late UploadPart / Complete / Abort calls surface NoSuchUpload." }),
            new("DeleteBucket", OperationStatus.Implemented, new[] { "Azure: DELETE https://{account}.blob.core.windows.net/{container}?restype=container", "Diff: Azure container delete is asynchronous; subsequent CreateContainer on the same name may return ContainerBeingDeleted (mapped to OperationAborted).", "Diff: S3 BucketNotEmpty is mapped from Azure ConditionNotMet/Conflict cases that surface only when the container retention policy intervenes." }),
            new("DeleteBucketCors", OperationStatus.Stub, new[] { "Azure: (no equivalent — proxy treats it as a no-op)" }),
            new("DeleteBucketEncryption", OperationStatus.Partial, new[] { "Azure: Conditional container-metadata update", "Diff: Deleting the intent does not disable or reconfigure Azure encryption.", "Diff: A subsequent GetBucketEncryption returns the synthetic default SSE-S3 AES256 configuration." }),
            new("DeleteBucketLifecycle", OperationStatus.Stub, new[] { "Azure: (no equivalent — proxy treats it as a no-op)" }),
