            new("DeleteObjectTagging", OperationStatus.Implemented, new[] { "Azure: PUT {blob}?comp=tags with an empty <TagSet/>", "Diff: Returns 204 No Content matching the S3 spec.", "Diff: Version selection requires account-level Blob versioning enabled out-of-band.", "Diff: Azure BlobVersionNotFound maps to S3 NoSuchVersion." }),
