            new("GetObject", OperationStatus.Implemented, new[] { "Azure: GET https://{account}.blob.core.windows.net/{container}/{blob}", "Diff: Streaming end-to-end: response body is forwarded without buffering.", "Diff: x-amz-id-2 carries the Azure x-ms-request-id for cross-system tracing.", "Diff: Presigned URLs are accepted (see PresignedUrl.yaml); the client must sign against the proxy host, and response-content-* query overrides are not honoured.", "Diff: Error responses omit the server-side x-amz-id-2 correlation header that real S3 emits. [conformance:missing-header:x-amz-id-2]", "Diff: Error envelopes omit the <HostId> element that real S3 emits. [conformance:missing-field:HostId]", "Diff: NoSuchBucket envelopes omit the informational <BucketName> element real S3 includes. [conformance:nosuchbucket-get-object::missing-field:BucketName]", "Diff: NoSuchKey envelopes omit the informational <Key> element real S3 includes. [conformance:nosuchkey-get-object::missing-field:Key]", "Diff: PreconditionFailed envelopes omit the informational <Condition> element (e.g. <Condition>If-Match</Condition>) real S3 includes. [conformance:precondition-failed-get::missing-field:Condition]" }),
