            new("PutObject", OperationStatus.Implemented, new[] { "Azure: PUT https://{account}.blob.core.windows.net/{container}/{blob}", "Diff: ETag value comes from Azure (hex of MD5 for single-part uploads); shape matches S3 but bytes differ from a re-uploaded object.", "Diff: PUT always overwrites an existing blob, matching S3 default semantics.", "Diff: Concrete-ETag preconditions (If-Match / If-None-Match with a value other than '*') return 501 NotImplemented: proxy-translated S3 ETags do not round-trip back to Azure's raw ETag space, and supporting optimistic concurrency would require a HEAD-then-PUT cycle that is not yet implemented. The '*' sentinel is honored (forwarded to Azure).", "Diff: Presigned PUT is accepted (see PresignedUrl.yaml). Body integrity is not signature-protected (UNSIGNED-PAYLOAD) — identical to AWS S3 semantics." }),
            new("PutObjectAcl", OperationStatus.Partial, new[] { "Azure: (no Azure equivalent — validates owner-only intent and replies 200)", "Diff: The versionId selects the object existence check only; Azure stores no S3 ACL document.", "Diff: Azure BlobVersionNotFound maps to S3 NoSuchVersion." }),
            new("PutObjectLegalHold", OperationStatus.Implemented, new[] { "Azure: Set Blob Legal Hold (PUT blob ?comp=legalhold, x-ms-legal-hold)", "Diff: Verified against real Azure only - Azurite does not support legal hold." }),
            new("PutObjectLockConfiguration", OperationStatus.Unsupported, new[] { "Azure: (bucket-level WORM is ARM/management-plane only; proxy returns 501 NotImplemented)", "Diff: PUT returns HTTP 501 NotImplemented to make the absence explicit; the matching GET returns the documented 'never configured' shape." }),
            new("PutObjectRetention", OperationStatus.Implemented, new[] { "Azure: Set Blob Immutability Policy (PUT blob ?comp=immutabilityPolicies)", "Diff: Azure locked policies are irreversible and extend-only; bypassing/shortening COMPLIANCE is rejected by Azure as in S3.", "Diff: Requires the storage account to have version-level immutability + blob versioning enabled (operator-provisioned via ARM); opt-in per topology.", "Diff: Verified against real Azure only - Azurite does not support immutability policies." }),
            new("PutObjectTagging", OperationStatus.Implemented, new[] { "Azure: PUT {blob}?comp=tags", "Diff: AWS uses 200 OK with empty body; the proxy matches that.", "Diff: Version selection depends on Azure Blob versioning being enabled by the operator.", "Diff: Azure BlobVersionNotFound maps to S3 NoSuchVersion." }),
            new("PutPublicAccessBlock", OperationStatus.Partial, new[] { "Azure: Conditional container-metadata update (persisted compatibility intent only)", "Diff: The AWS document round-trips for compatibility but has no enforcement effect." }),
            new("RestoreObject", OperationStatus.Unsupported, new[] { "Azure: (no equivalent — proxy returns 501 NotImplemented)" }),
            new("UploadPart", OperationStatus.Implemented, new[] { "Azure: Put Block (?comp=block&blockid=…)", "Diff: Block IDs use the fixed-width layout b{nonce16hex}p{partNumber5d} (base64-encoded) so all parts of a blob share a constant length, satisfying Azure's per-blob block-ID uniformity rule.", "Diff: Part numbers must be in [1, 10000] (S3 limit). Azure supports up to 50,000 blocks per blob — surplus capacity is unused." }),
            new("UploadPartCopy", OperationStatus.Implemented, new[] { "Azure: Put Block From URL (?comp=block&blockid=…)", "Diff: Per-part ETag is synthesised from the (uploadId, partNumber) pair (same algorithm ListParts uses), NOT the MD5 of the copied bytes. Azure's Put Block From URL response only includes Content-MD5 when the request supplied x-ms-source-content-md5; otherwise it returns x-ms-content-crc64, which has no S3 equivalent. The synthetic ETag is stable per (uploadId, partNumber) and is what the proxy expects to see echoed back in CompleteMultipartUpload — but it is NOT a content hash and must not be compared with the per-part ETag returned by a non-copy UploadPart.", "Diff: UploadPartCopy with source==destination (same bucket+key) is rejected with InvalidRequest. Azure would otherwise stage the new block on the source blob itself, letting the eventual CompleteMultipartUpload silently reconcile against a moving target.", "Diff: Source URL SAS expires 1 hour after the UploadPartCopy request; a very large source copied over a very slow link could theoretically race the expiry. In practice Azure's intra-account server-side fetch is fast enough that this is academic.", "Diff: Integration tests against Azurite skip the end-to-end happy-path scenarios because Azurite does not implement Put Block From URL (responds 501 InternalError). The implementation is verified against real Azure Blob Storage in the cloud-integration nightly." }),
        });

    public static readonly CapabilityMatrix SecretsManager = new(
        ServiceName: "secretsmanager",
        Operations: new OperationCapability[]
        {
            new("CreateSecret", OperationStatus.Implemented, new[] { "Azure: PUT https://{vault}.vault.azure.net/secrets/{name}", "Diff: Initial MVP uses Key Vault AAD auth and translates the core secret CRUD/read paths to AWS Secrets Manager JSON responses.", "Diff: Advanced rotation, restore, and policy semantics are not yet modeled; the proxy uses Key Vault secret versions as the AWS version surface.", "Diff: Responses use the AWS JSON 1.1 wire shape (Unix-epoch numeric timestamps, Content-Type application/x-amz-json-1.1); validated end-to-end against a real Azure Key Vault through the proxy with the AWS SDK.", "Diff: Input Tags are accepted in the AWS Key/Value array shape (as sent by the AWS SDK) and mapped to the Key Vault tags map; an existing-name conflict (including Key Vault 409) maps to ResourceExistsException.", "Diff: The aws2azure- tag prefix is reserved for proxy-owned version metadata and is stripped from caller-supplied tags before writing to Key Vault." }),
            new("DeleteSecret", OperationStatus.Implemented, new[] { "Azure: DELETE https://{vault}.vault.azure.net/secrets/{name}", "Diff: Initial MVP uses Key Vault AAD auth and translates the core secret CRUD/read paths to AWS Secrets Manager JSON responses.", "Diff: Advanced rotation, restore, and policy semantics are not yet modeled; the proxy uses Key Vault secret versions as the AWS version surface.", "Diff: Responses use the AWS JSON 1.1 wire shape (Unix-epoch numeric timestamps, Content-Type application/x-amz-json-1.1); validated end-to-end against a real Azure Key Vault through the proxy with the AWS SDK." }),
            new("DescribeSecret", OperationStatus.Implemented, new[] { "Azure: GET https://{vault}.vault.azure.net/secrets/{name}?api-version=7.4", "Diff: Initial MVP uses Key Vault AAD auth and translates the core secret CRUD/read paths to AWS Secrets Manager JSON responses.", "Diff: Advanced rotation, restore, and policy semantics are not yet modeled; the proxy uses Key Vault secret versions as the AWS version surface.", "Diff: Responses use the AWS JSON 1.1 wire shape (Unix-epoch numeric timestamps, Content-Type application/x-amz-json-1.1); validated end-to-end against a real Azure Key Vault through the proxy with the AWS SDK.", "Diff: Tags are returned as an AWS Key/Value array sourced from the Key Vault secret's tags map.", "Diff: VersionIdsToStages is built from the complete paginated Key Vault version inventory. Deterministic same-token duplicates are collapsed to one logical AWS VersionId; conflicting token payload metadata returns ResourceExistsException." }),
            new("GetSecretValue", OperationStatus.Implemented, new[] { "Azure: GET https://{vault}.vault.azure.net/secrets/{name}/versions/{version?}", "Diff: Initial MVP uses Key Vault AAD auth and translates the core secret CRUD/read paths to AWS Secrets Manager JSON responses.", "Diff: Advanced rotation, restore, and policy semantics are not yet modeled; the proxy uses Key Vault secret versions as the AWS version surface.", "Diff: Responses use the AWS JSON 1.1 wire shape (Unix-epoch numeric timestamps, Content-Type application/x-amz-json-1.1); validated end-to-end against a real Azure Key Vault through the proxy with the AWS SDK.", "Diff: VersionStage lookup scans proxy-owned Key Vault version tags written by PutSecretValue; untagged legacy versions are treated as AWSCURRENT fallback for default reads. VersionId accepts either a raw Key Vault version id or a PutSecretValue ClientRequestToken, and VersionId+VersionStage requests are rejected when they do not refer to the same version. Full AWS rotation workflows such as RotateSecret are not implemented.", "Diff: Version and token resolution use the same complete paginated inventory and deterministic created-time/version-id ordering as the write reconciler. If multiple physical versions still hold the requested explicit label, GetSecretValue returns ResourceExistsException instead of silently choosing an ambiguous winner." }),
            new("ListSecrets", OperationStatus.Implemented, new[] { "Azure: GET https://{vault}.vault.azure.net/secrets?api-version=7.4", "Diff: Initial MVP uses Key Vault AAD auth and translates the core secret CRUD/read paths to AWS Secrets Manager JSON responses.", "Diff: Advanced rotation, restore, and policy semantics are not yet modeled; the proxy uses Key Vault secret versions as the AWS version surface.", "Diff: Responses use the AWS JSON 1.1 wire shape (Unix-epoch numeric timestamps, Content-Type application/x-amz-json-1.1); validated end-to-end against a real Azure Key Vault through the proxy with the AWS SDK.", "Diff: SecretList entries emit Tags as an AWS Key/Value array and resolve the secret Name/ARN from the Key Vault item id; a JSON-map tag shape would desync the AWS SDK list unmarshaller.", "Diff: Pagination: AWS NextToken carries the Key Vault $skiptoken continuation value (and MaxResults maps to Key Vault maxresults); the proxy always rebuilds its own vault URI from the token rather than following an inbound URL, so NextToken cannot be used as an SSRF vector." }),
            new("PutSecretValue", OperationStatus.Partial, new[] { "Azure: PUT https://{vault}.vault.azure.net/secrets/{name}", "Diff: Initial MVP uses Key Vault AAD auth and translates PutSecretValue to a Key Vault Set Secret request that creates a new Key Vault secret version.", "Diff: The proxy first checks that the secret exists and returns ResourceNotFoundException when it does not, matching AWS PutSecretValue semantics instead of Key Vault's native upsert.", "Diff: ClientRequestToken metadata, payload hashes, intended stages, and transition mode are stored on Key Vault versions. Physical duplicates with the same token and payload are resolved deterministically; conflicting payloads and an invariant that remains unobserved after bounded repair return ResourceExistsException with AWS's HTTP 400 JSON shape.", "Diff: New versions are created with an explicit empty stage set. After the version is visible in the complete paginated inventory, requested labels are removed from losers before the winner is published. Every PATCH starts from a fresh version GET so unrelated Key Vault tags are retained, and a bounded verification pass repairs transient visibility or partial-patch failures.", "Diff: Strict atomicity across proxy instances remains partial: Key Vault has no transaction covering create/list/multi-version tag updates, and this design intentionally adds no external coordinator or state store.", "Diff: The Key Vault PUT payload deliberately omits attributes.created so Key Vault preserves the original secret creation timestamp reported by DescribeSecret/GetSecretValue.", "Diff: Source real-Azure scenarios cover rapid cross-instance same-token writes, out-of-band Key Vault tag interference, proxy restart replay, and rollback replay. Evidence regeneration and workflow execution are owned separately; the operation remains partial because strict cross-instance atomicity is structurally unavailable in Key Vault alone." }),
            new("RotateSecret", OperationStatus.Unsupported, new[] { "Azure: None — Azure Key Vault has no equivalent managed-rotation trigger the proxy can drive", "Diff: Returns HTTP 501 with an AWS `NotImplementedException` error shape and a message directing operators to rotate out-of-band and publish the new value via PutSecretValue, or to manage rotation directly in Azure Key Vault. The action is recognised by the wire-protocol router (so it surfaces in metrics) but is rejected before backend credentials are resolved — it is deliberately unsupported, not merely unimplemented." }),
            new("UpdateSecret", OperationStatus.Implemented, new[] { "Azure: PUT https://{vault}.vault.azure.net/secrets/{name}/versions", "Diff: Initial MVP uses Key Vault AAD auth and translates the core secret CRUD/read paths to AWS Secrets Manager JSON responses.", "Diff: Advanced rotation, restore, and policy semantics are not yet modeled; the proxy uses Key Vault secret versions as the AWS version surface.", "Diff: Responses use the AWS JSON 1.1 wire shape (Unix-epoch numeric timestamps, Content-Type application/x-amz-json-1.1); validated end-to-end against a real Azure Key Vault through the proxy with the AWS SDK.", "Diff: Because Key Vault PUT is an upsert, UpdateSecret first checks existence and returns ResourceNotFoundException for a missing secret to match AWS semantics.", "Diff: ClientRequestToken is persisted and replayed through the shared version coordinator. ResourceExistsException uses the AWS HTTP 400 JSON shape.", "Diff: The operation remains partial because strict cross-instance version/stage atomicity is impossible without an external coordinator, which this Key Vault-only design intentionally avoids." }),
        });

    public static readonly CapabilityMatrix Sns = new(
        ServiceName: "sns",
        Operations: new OperationCapability[]
        {
            new("ConfirmSubscription", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic subscriptions", "Diff: SNS confirmation tokens are not validated against an out-of-band challenge flow.", "Diff: Arbitrary, cross-topic, missing, and non-deterministic subscription tokens are rejected; the operation does not synthesize a fallback identifier.", "Diff: ConfirmSubscription applies to the Service Bus subscription-management profile only and does not confirm Azure Event Grid event subscriptions." }),
            new("CreateTopic", OperationStatus.Partial, new[] { "Azure: Azure Service Bus Topics management REST API", "Diff: TopicArn is proxy-synthesised as arn:aws:sns:{sigv4-region}:000000000000:{topicName}. The account id is a stable placeholder because the proxy is not backed by an AWS account namespace.", "Diff: Only the basic topic name is honoured on create. Topic attributes supplied in the CreateTopic request are ignored for now; Azure Service Bus topic properties stay at service defaults until a later slice implements attribute mapping.", "Diff: When an SNS topic is configured with backend=EventGrid, aws2azure still creates the backing Azure Service Bus topic in this slice because subscription metadata continues to live on Service Bus. Event Grid only handles Publish / PublishBatch.", "Diff: FIFO topic semantics are deferred. This slice only accepts the non-FIFO name subset [A-Za-z0-9_-]{1,256}; .fifo names are rejected instead of creating a FIFO-equivalent Azure entity.", "Diff: Service Bus topic names are further constrained by Azure. The proxy currently validates the AWS-side subset above and does not yet surface Azure's narrower length/character restrictions separately." }),
            new("DeleteTopic", OperationStatus.Partial, new[] { "Azure: Azure Service Bus Topics management REST API", "Diff: DeleteTopic accepts only proxy-shaped ARNs of the form arn:aws:sns:{region}:{accountId}:{topicName}. The proxy currently synthesises accountId as 000000000000, but delete only uses the topic-name suffix when translating to Azure.", "Diff: The same FIFO gap as CreateTopic applies: .fifo ARNs are rejected because FIFO semantics are deferred to a later slice.", "Diff: Azure deletes are asynchronous underneath Service Bus. A successful DeleteTopic response means the topic was accepted for deletion, not necessarily that every broker-side artifact is already gone." }),
            new("GetSubscriptionAttributes", OperationStatus.Partial, new[] { "Azure: Azure Service Bus subscription description", "Diff: Protocol and Endpoint come from aws2azure's UserMetadata blob rather than native Service Bus subscription fields. Missing or invalid UserMetadata falls back to empty strings and RawMessageDelivery=false.", "Diff: ConfirmationWasAuthenticated is always true and PendingConfirmation is always false because this slice auto-confirms subscriptions.", "Diff: FilterPolicy is returned from stored UserMetadata only. FilterPolicyScope defaults to MessageAttributes when a stored filter policy has no explicit scope.", "Diff: DeliveryPolicy, EffectiveDeliveryPolicy, and RedrivePolicy are omitted because Service Bus delivery and dead-letter settings do not match the SNS attribute shapes exposed by this API.", "Diff: Attributes are read from Azure Service Bus subscriptions only; Azure Event Grid event-subscription properties are explicitly outside this profile." }),
            new("GetTopicAttributes", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic description", "Diff: DisplayName is always returned as an empty string because Service Bus topics do not expose an SNS-style display name.", "Diff: Policy is returned as '{}' and DeliveryPolicy / EffectiveDeliveryPolicy are omitted because this slice does not translate SNS policies onto Azure authorization or delivery settings.", "Diff: SubscriptionsConfirmed is populated from Service Bus SubscriptionCount. Pending and deleted counts are always reported as 0 because aws2azure auto-confirms subscriptions and Service Bus does not expose the SNS lifecycle split.", "Diff: KmsMasterKeyId is returned empty because Service Bus encryption is configured at the namespace level, not per topic.", "Diff: FifoTopic is inferred from a '.fifo' suffix or RequiresDuplicateDetection=true, and ContentBasedDeduplication is mapped directly from RequiresDuplicateDetection. This is only an approximation of SNS FIFO semantics.", "Diff: AWS-only attributes such as SignatureVersion and TracingConfig are omitted." }),
            new("ListSubscriptions", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic subscriptions", "Diff: NextToken is a versioned, HMAC-SHA256-signed opaque cursor containing the current topic and subscription offsets. The AWS binding secret supplies the stable signing key, so tokens survive proxy restart while forged, tampered, and wrong-operation tokens are rejected.", "Diff: Listing all subscriptions requires cross-topic enumeration over the Service Bus management plane and can be more expensive than native SNS ListSubscriptions.", "Diff: Only Azure Service Bus topic subscriptions are enumerated. Azure Event Grid event subscriptions are explicitly excluded." }),
            new("ListSubscriptionsByTopic", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic subscriptions", "Diff: NextToken is a versioned, HMAC-SHA256-signed opaque cursor bound to ListSubscriptionsByTopic and the exact topic name. Tokens survive restart with the same AWS binding secret; tampering, cross-operation use, and reuse for another topic are rejected.", "Diff: Only Azure Service Bus topic subscriptions are enumerated. Azure Event Grid event subscriptions are explicitly excluded." }),
            new("ListTopics", OperationStatus.Partial, new[] { "Azure: Azure Service Bus Topics management REST API", "Diff: TopicArn values are proxy-synthesised as arn:aws:sns:{sigv4-region}:000000000000:{topicName}. The account id is a stable placeholder, not an AWS account namespace.", "Diff: NextToken is an opaque base64-encoded Service Bus skip counter, not an AWS-compatible cursor. Tokens only preserve the next $skip offset and do not encode any other AWS pagination semantics.", "Diff: Pagination is fixed to Azure's $top=100 management page size for this slice. When Azure returns exactly 100 topics the proxy emits NextToken=base64(skip+100); otherwise NextToken is omitted.", "Diff: FIFO topic distinction is deferred. Topics created out of band with .fifo suffixes are not specially modelled and the slice does not surface FIFO-only metadata." }),
            new("Publish", OperationStatus.Partial, new[] { "Azure: Azure Service Bus Topics / Azure Event Grid", "Diff: MessageId is a proxy-generated GUID, not an AWS-generated SNS identifier.", "Diff: SequenceNumber is returned empty because neither Azure Service Bus nor Azure Event Grid exposes an SNS-compatible sequence number on publish.", "Diff: MessageStructure=json is passed through as-is; the proxy does not filter per-protocol payloads yet.", "Diff: On the Service Bus Topics backend, MessageAttributes encode DataType in a parallel application property named '{Name}.DataType' so AWS-style attributes can be reconstructed by downstream consumers.", "Diff: On the Event Grid backend, the proxy emits the classic Event Grid schema with eventType=aws.sns.Message; CloudEvents-formatted Event Grid topics are not supported in this slice.", "Diff: On the Event Grid backend, MessageAttributes are emitted inside data.MessageAttributes as { Type, Value } objects.", "Diff: On the Event Grid backend, the Event Grid envelope subject is always the SNS TopicArn; the AWS Subject parameter is copied into data.Subject.", "Diff: On the Event Grid backend, HTTP-level publish failures are mapped to SNS per-message failure semantics by the proxy; Publish returns an SNS error while PublishBatch marks each affected entry failed.", "Diff: Subject is exposed both as the AMQP subject property and as the 'aws.sns.Subject' application property on the Service Bus Topics backend.", "Diff: MessageDeduplicationId is forwarded as the 'x-opt-deduplication-id' application property on the Service Bus Topics backend rather than a broker-native send-side field.", "Diff: MessageGroupId / MessageDeduplicationId FIFO semantics are not honoured on the Event Grid backend; the proxy drops them, logs a warning, and continues.", "Diff: Azure Service Bus and Event Grid message size limits differ from SNS; Event Grid classic schema also enforces 1 MB per event and 1 MB per HTTP batch." }),
            new("PublishBatch", OperationStatus.Partial, new[] { "Azure: Azure Service Bus Topics / Azure Event Grid", "Diff: MessageId values are proxy-generated GUIDs, not AWS-generated SNS identifiers.", "Diff: SequenceNumber is returned empty because neither Azure Service Bus nor Azure Event Grid exposes an SNS-compatible sequence number on publish.", "Diff: MessageStructure=json is passed through as-is; the proxy does not filter per-protocol payloads yet.", "Diff: On the Service Bus Topics backend, MessageAttributes encode DataType in a parallel application property named '{Name}.DataType' so AWS-style attributes can be reconstructed by downstream consumers.", "Diff: On the Event Grid backend, the proxy emits the classic Event Grid schema with eventType=aws.sns.Message; CloudEvents-formatted Event Grid topics are not supported in this slice.", "Diff: On the Event Grid backend, MessageAttributes are emitted inside data.MessageAttributes as { Type, Value } objects.", "Diff: On the Event Grid backend, returned MessageId values are the proxy-generated GUIDs used as the Event Grid envelope id fields.", "Diff: On the Event Grid backend, HTTP-level failures are mapped to per-entry Failed results for every message in the affected HTTP batch, even though Event Grid itself accepts or rejects each POST atomically.", "Diff: On the Event Grid backend, MessageGroupId / MessageDeduplicationId FIFO semantics are not honoured; the proxy drops them, logs a warning, and continues.", "Diff: PublishBatch uses best-effort per-entry outcomes over AMQP and proxied per-entry outcomes over Event Grid; partial-failure behavior can differ from AWS SNS semantics.", "Diff: Azure Service Bus and Event Grid message size limits differ from SNS; Event Grid classic schema also enforces 1 MB per event, 1 MB per HTTP batch, and 5000 events per POST." }),
            new("SetSubscriptionAttributes", OperationStatus.Partial, new[] { "Azure: Azure Service Bus subscription description", "Diff: FilterPolicy is stored only in UserMetadata in this slice. Service Bus rule-based filtering is not programmed yet, so enforcement is deferred to a later forwarding slice.", "Diff: FilterPolicyScope accepts MessageAttributes and MessageBody, but MessageBody scope is only persisted; it is not enforced yet.", "Diff: DeliveryPolicy, RedrivePolicy, and SubscriptionRoleArn are accepted as no-ops because Service Bus does not expose a matching SNS attribute contract here.", "Diff: Updates preserve mutable SubscriptionDescription property XML, replace only UserMetadata, and send If-Match: * because Service Bus subscriptions do not expose usable per-entity ETags. Concurrent Azure-side writers are therefore last-write-wins; read-only runtime properties are never replayed.", "Diff: Updates that would push the serialized UserMetadata payload beyond Service Bus's 1024-character limit are rejected with InvalidParameter.", "Diff: Unknown AWS attribute names return InvalidParameter.", "Diff: Only Azure Service Bus subscription descriptions are updated; Azure Event Grid event-subscription properties are explicitly outside this profile." }),
            new("SetTopicAttributes", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic description", "Diff: DisplayName, Policy, DeliveryPolicy, EffectiveDeliveryPolicy, KmsMasterKeyId, SignatureVersion, and TracingConfig do not have a direct Service Bus topic equivalent in this slice and are treated as no-ops.", "Diff: ContentBasedDeduplication is backed by RequiresDuplicateDetection, but Service Bus does not allow changing that property after topic creation. aws2azure returns InvalidParameter instead of attempting an in-place update.", "Diff: Unknown AWS attribute names return InvalidParameter." }),
            new("Subscribe", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic subscriptions", "Diff: HTTPS / HTTP subscriptions are auto-confirmed immediately. SNS token-based confirmation is not implemented in this slice.", "Diff: When a deterministic subscription already exists but its stored metadata differs from the new Subscribe request, aws2azure returns the existing ARN and logs a warning instead of replacing the subscription.", "Diff: Only sqs, https, and http protocols are accepted. email, email-json, sms, lambda, application, and firehose are rejected with InvalidParameter.", "Diff: Subscribe manages Azure Service Bus topic subscriptions only. It never creates or updates an Azure Event Grid event subscription; Event Grid subscription semantics are explicitly outside this profile.", "Diff: Subscribers do not receive actively-pushed deliveries: aws2azure is publish-only and never forwards messages out to HTTPS/HTTP endpoints or SQS-backed queues (see the 'Subscriber delivery forwarder' sub-feature — won't implement, out of scope). Messages are readable from the backing Service Bus subscription by a native Azure consumer. Event Grid-backed SNS topics do not fan out to the Service Bus subscriptions created here.", "Diff: The Microsoft Service Bus emulator does not persist or echo subscription UserMetadata, where this proxy stores Protocol/Endpoint/FilterPolicy/RawMessageDelivery. Emulator-backed integration tests therefore skip the subscription lifecycle assertions; correctness is validated against real Azure Service Bus." }),
            new("Unsubscribe", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic subscriptions", "Diff: Unsubscribe is idempotent: HTTP 200/204/404 from Service Bus all return SNS success.", "Diff: Only the mapped Azure Service Bus topic subscription is deleted. Azure Event Grid event subscriptions are explicitly outside this profile." }),
        });

    public static readonly CapabilityMatrix Sqs = new(
        ServiceName: "sqs",
        Operations: new OperationCapability[]
        {
            new("AddPermission", OperationStatus.Stub, new[] { "Azure: No native Service Bus equivalent — validates queue existence and returns success.", "Diff: The Permission payload is accepted and silently dropped; there is no AWS-style cross-account access control inside the proxy. Clients relying on AddPermission to grant access should configure SB SAS rules or Azure RBAC out of band, then map them to aws2azure access keys via the config file.", "Diff: Returns 200 OK on any well-formed payload to maximise SDK compatibility — including for Actions that SQS itself rejects on standard queues. A future revision may tighten validation once the credential model exposes scoped keys." }),
            new("ChangeMessageVisibility", OperationStatus.Partial, new[] { "Azure: Azure Service Bus queue runtime REST API — POST /{queue}/messages/{messageId}/{lockToken}?api-version=2021-05 (renew-lock); AMQP — `com.microsoft:renew-lock` over the queue's `$management` request-response link; visibility=0 maps to AMQP Abandon on the receiver link.", "Diff: SB renew-lock semantics do not accept a caller-supplied duration — every renew extends by the queue's LockDuration. When the requested timeout differs from what SB grants the proxy emits the Aws2Azure-VisibilityClamped: requested=<N>;granted=<M> diagnostic header. (The header is suppressed when they agree — typical for queues whose LockDuration equals the SDK default 30 s called with VisibilityTimeout=30.)", "Diff: VisibilityTimeout=0 is supported on the AMQP transport via Abandon (immediate release, redelivery counter incremented). It is NOT supported on the REST transport — the renew still extends the lock; clients needing immediate release on REST must DeleteMessage or wait for the lock to expire.", "Diff: Verified against in-process fakes; emulator-backed end-to-end validation lands with the Service Bus emulator fixture work.", "Diff: Header format: granted-seconds is derived from `lockedUntil - DateTimeOffset.UtcNow` (rounded to whole seconds). Clock skew between the proxy host and Service Bus can shift the value by 1-2 s; consumers should treat it as a diagnostic hint, not an SLA.", "Diff: Emulator divergence: the Service Bus emulator's $management node detaches the request/response link on the first com.microsoft:renew-lock request (visible to the proxy as 'channel has been closed'). Validated against real Azure only; the integration test against the emulator is skipped with a SkipException pointing to the real-Azure smoke." }),
            new("ChangeMessageVisibilityBatch", OperationStatus.Partial, new[] { "Azure: Azure Service Bus queue runtime REST API — N parallel POST /{queue}/messages/{messageId}/{lockToken}?action=renewlock&api-version=2021-05", "Diff: SB has no per-call visibility override on REST. The proxy validates and accepts the VisibilityTimeout value but SB always extends by the queue's LockDuration. Callers needing an arbitrary new visibility must Delete+Send or rely on SetQueueAttributes to change the queue-wide LockDuration.", "Diff: VisibilityTimeout of 0 (which AWS uses to make a message immediately re-visible) is currently treated as a renewlock too — the message is not made re-visible. This divergence is tracked for Phase-2 NFR follow-up.", "Diff: Verified against in-process fakes; emulator-backed end-to-end validation lands with the SbEmulatorFixture build-out (tracked in p2-sb-emulator-fixture).", "Diff: AMQP transport (Phase 2.5): when a queue is configured with `transport: Amqp`, ChangeMessageVisibilityBatch routes to the AMQP path — each entry with VisibilityTimeout=0 abandons via the cached (session) receiver, restoring the SQS 'immediately re-visible' semantics on this path (closing the divergence above for AMQP queues). Positive VisibilityTimeout values RenewLock via the SB `$management` link (session-aware for v3 receipt handles); SB clamping is silent in the batch shape (the singular CMV emits the `Aws2Azure-VisibilityClamped` header but the batch response has no per-entry place to carry it)." }),
            new("CreateQueue", OperationStatus.Implemented, new[] { "Azure: PUT https://{namespace}.servicebus.windows.net/{queue}?api-version=2021-05 (Atom QueueDescription)", "Diff: Queue name validation enforces SQS rules (1-80 alnum/-_, '.fifo' suffix) before reaching Azure; Azure container names are stricter on some characters.", "Diff: Idempotency: an existing queue with matching attributes returns the same QueueUrl; mismatched attributes surface QueueNameExists. We compare LockDuration, TTL, MaxMessageSize, RequiresSession, RequiresDuplicateDetection — a small set vs SQS's full attribute parity.", "Diff: Core standard-queue creation is validated against real Azure Service Bus; FIFO session receive remains a separately documented gap and blocks SendMessage/ReceiveMessage seals." }),
            new("DeleteMessage", OperationStatus.Implemented, new[] { "Azure: Azure Service Bus queue runtime REST API — DELETE /{queue}/messages/{messageId}/{lockToken}?api-version=2021-05", "Diff: If the SB lock has expired before DeleteMessage arrives, the proxy returns ReceiptHandleIsInvalid (404). AWS SQS would return success (idempotent) for already-deleted messages and an error only for genuinely invalid handles — these two cases are indistinguishable on SB REST without an extra round-trip.", "Diff: The standard-queue delete path is validated against real Azure Service Bus through the message-lifecycle conformance scenario; FIFO settlement remains covered by the separate FIFO gap.", "Diff: AMQP transport (Phase 2.5 slice 8b.4c): when the queue is configured with `transport: Amqp`, DeleteMessage settles the in-flight delivery via the AMQP `accepted` outcome against the cached receiver (via the lock-token in-flight cache landed in slice 8b.4b). Cache miss — already settled, lock expired, sender-settled at receive, or delivery came from a torn-down receiver instance — surfaces as ReceiptHandleIsInvalid, identical to the REST path's 404→ReceiptHandleIsInvalid mapping. Receipt handles minted by the AMQP path (version `2`) are rejected if presented to a REST-configured queue and vice versa — a queue's transport setting is part of the handle's contract.", "Diff: Real-Azure GA qualification for sqs-standard-messaging (issue #626, runs 29854940190, 29855796892, 29856877991) exercises a REST-transport rollback counterpart (`rollback-rest`, supplementary, non-required) that receives on the REST lane before a sealed candidate→prior restart and attempts DeleteMessage after. Across all three runs the REST receipt handle did not redeem after the restart-cycle wall-clock gap — consistent with the expired-lock behavior documented above (Service Bus locks are time-bound broker-side regardless of transport, so a restart long enough to cross that window invalidates a REST handle the same way it invalidates an AMQP one), not evidence of a proxy defect. The graded/required proof for this profile is the AMQP `rollback` scenario (link-scoped receiver boundary), which passed all three runs; `rollback-rest` remains supplementary evidence, kept out of the reviewed qualification policy's scenario set." }),
            new("DeleteMessageBatch", OperationStatus.Implemented, new[] { "Azure: Azure Service Bus queue runtime REST API — N parallel DELETE /{queue}/messages/{messageId}/{lockToken}?api-version=2021-05", "Diff: SB REST has no native batch-delete; the proxy fans out parallel DELETEs. A failing entry never aborts the batch — callers see per-entry results matching SQS semantics.", "Diff: Expired-lock vs already-deleted ambiguity from DeleteMessage applies per entry (see DeleteMessage.yaml behavior_differences).", "Diff: Standard-queue batch deletion is validated against real Azure Service Bus with per-entry success and failure evidence; FIFO AMQP settlement remains subject to the separate FIFO gap.", "Diff: AMQP transport (Phase 2.5): when a queue is configured with `transport: Amqp`, DeleteMessageBatch routes to the AMQP path — each entry decodes the v2/v3 AMQP receipt handle minted by AMQP ReceiveMessage, looks up the cached (session) receiver via the lock-token cache, and calls `ServiceBusReceiver.CompleteAsync`. FIFO-aware: entries with different session-ids fan out to their own cached session receivers in parallel. Per-entry failures (stale handle, queue mismatch, cache miss, transport error) are surfaced as BatchResultErrorEntry items just like the REST path." }),
            new("DeleteQueue", OperationStatus.Implemented, new[] { "Azure: DELETE https://{namespace}.servicebus.windows.net/{queue}?api-version=2021-05", "Diff: Service Bus deletes the queue synchronously; AWS SQS may take up to 60 seconds of eventual consistency before the queue stops accepting messages. Callers that delete-then-recreate within seconds may need to retry on QueueDeletedRecently — not currently surfaced by the proxy.", "Diff: Unknown-queue 404 is mapped to AWS.SimpleQueueService.NonExistentQueue (HTTP 400) per SQS spec.", "Diff: Validated against real Azure Service Bus through the standard queue/message lifecycle scenario.", "Diff: Existence-probe eventual consistency after DeleteQueue (issue #626): two independent production-shaped real-Azure GA load runs (2026-07-21, runs 29843180286 and 29847167581) observed a GetQueueUrl existence probe continuing to find a queue for over both a one-minute and a three-minute budget after its DeleteQueue call had already returned success, on a namespace with many other queues churning concurrently from the same run's representative-load workers. Service Bus's DELETE call itself is synchronous for the data plane, but the management-plane read path a GetQueueUrl existence probe uses can lag behind that delete, mirroring the ListQueues creation-lag caveat documented in docs/gaps/sqs/ListQueues.yaml — except here no empirically observed upper bound held across two real attempts, so it cannot be turned into a reliable, bounded qualification gate the way the ListQueues caveat was. The rollback qualification therefore deletes the queue as best-effort cleanup (matching PurgeQueue's own best-effort framing) without asserting a bounded existence-probe absence; this is not a proxy defect and does not weaken the rollback scenario's actual proof, which completes before this cleanup step." }),
            new("GetQueueAttributes", OperationStatus.Partial, new[] { "Azure: GET https://{namespace}.servicebus.windows.net/{queue}?api-version=2021-05 (Atom QueueDescription)", "Diff: AttributeNames filtering happens proxy-side after the full Atom response is parsed.", "Diff: Verified against Service Bus emulator only; real-Azure validation pending." }),
            new("GetQueueUrl", OperationStatus.Implemented, new[] { "Azure: GET https://{namespace}.servicebus.windows.net/{queue}?api-version=2021-05 (existence probe)", "Diff: Returned QueueUrl is '{request-scheme}://{request-host}/000000000000/{queue}' so the AWS SDK keeps routing back to the same proxy endpoint the caller reached.", "Diff: Existence check uses Service Bus GET; an unknown queue returns AWS.SimpleQueueService.NonExistentQueue.", "Diff: Validated against real Azure Service Bus through both the standard message lifecycle and queue discovery after proxy restart." }),
            new("ListDeadLetterSourceQueues", OperationStatus.Implemented, new[] { "Azure: Page through SB management GET /$Resources/queues?api-version=2021-05 and filter entries whose ForwardDeadLetteredMessagesTo equals the requested queue.", "Diff: Linear scan: the proxy issues one or more SB management GETs per ListDeadLetterSourceQueues call. On namespaces with thousands of queues this is O(N) and may be slow; the NFR phase should consider a cached reverse index.", "Diff: Verified against in-process fakes; emulator-backed validation is blocked (SB emulator does not expose management REST). Real-Azure verification pending.", "Diff: Verified against in-process fakes; emulator-backed validation is blocked (SB emulator does not expose management REST). Real-Azure verification pending." }),
            new("ListQueueTags", OperationStatus.Partial, new[] { "Azure: GET QueueDescription and decode aws2azure's base64 tag blob from UserMetadata.", "Diff: Tags are stored as an aws2azure-owned compact binary tag map, base64-encoded into Service Bus QueueDescription.UserMetadata. Azure-side tools will see the opaque base64 blob rather than individual tag keys.", "Diff: Service Bus UserMetadata is limited to roughly 1024 characters in the legacy management schema, so TagQueue may reject otherwise-valid SQS tag sets that cannot fit.", "Diff: Verified with in-process Service Bus management fakes. The Service Bus emulator does not validate or persist this management-plane UserMetadata path; real-Azure validation remains pending." }),
            new("ListQueues", OperationStatus.Implemented, new[] { "Azure: GET https://{namespace}.servicebus.windows.net/$Resources/queues?api-version=2021-05&$skip=N&$top=M", "Diff: Service Bus iteration is by $skip/$top; the cursor is not stable across queue deletions. AWS SQS tokens are likewise opaque, so no public contract is broken.", "Diff: Prefix filtering happens after the page is returned, so the same NextToken may visit a partially-filtered page. This is consistent with AWS-SDK pagination but may surface fewer than MaxResults entries per call.", "Diff: Pagination is validated against real Azure Service Bus across multiple management API pages.", "Diff: Eventual consistency shortly after CreateQueue (issue #626): real-Azure workload run 29790063721 observed 4 transient misses across 1,634 ListQueues attempts (~0.24%) when a worker listed immediately after CreateQueue against a live namespace — the freshly created queue was already usable for Send/ReceiveMessage but not yet visible on the Service Bus management ($Resources/queues) listing. This matches AWS's documented ListQueues eventual-consistency caveat and is not a proxy defect; load-testing and production clients should tolerate a short bounded propagation delay rather than treating a single miss as a hard failure." }),
            new("PurgeQueue", OperationStatus.Partial, new[] { "Azure: Azure Service Bus queue runtime REST API — emulated via drain-loop of POST /{queue}/messages/head + DELETE /{queue}/messages/{id}/{lockToken}", "Diff: SB has no native purge. The proxy emulates it by draining peek-locked messages and deleting them. With a long LockDuration the drain may not be able to keep up if producers are sending faster than the proxy can delete — the 60s budget bounds wall-clock cost; the queue is therefore best-effort empty rather than guaranteed empty at the end of the call. The SQS contract guarantees a 60-second 'all messages enqueued at the time of the call will be deleted' window, which we approximate.", "Diff: The 60-second cool-down (PurgeQueueInProgress) is in-process only. Other replicas of the proxy will not observe the cool-down — a horizontally scaled deployment could allow multiple concurrent drains. Tracked for the NFR phase (shared coordination cache).", "Diff: Verified against in-process fakes; emulator-backed end-to-end validation lands with the SbEmulatorFixture build-out (tracked in p2-sb-emulator-fixture)." }),
            new("ReceiveMessage", OperationStatus.Implemented, new[] { "Azure: Azure Service Bus queue runtime REST API — POST /{queue}/messages/head?timeout={waitSeconds}&api-version=2021-05 (peek-lock semantics)", "Diff: VisibilityTimeout on ReceiveMessage cannot be set per-call — SB locks the message for the queue's configured LockDuration. The proxy validates the parameter but does not enforce it; clients needing custom per-message visibility must use ChangeMessageVisibility after receive.", "Diff: MaxNumberOfMessages > 1 is emulated by looping POST /messages/head, capped by ReceiveLoopBudget (5s) added on top of WaitTimeSeconds — the proxy may return fewer messages than requested even when the queue has more if the budget elapses.", "Diff: ApproximateFirstReceiveTimestamp and SenderId are not surfaced (SB does not provide them).", "Diff: Long polling uses SB's native server-side wait; if the first call returns empty after the wait the receive returns immediately with an empty list (no second wait). This matches SQS semantics.", "Diff: FIFO ordering — AMQP vs REST: SQS FIFO guarantees strict per-MessageGroupId order on receive (one in-flight message per group at a time, others stay invisible until the in-flight one is deleted). This is IMPLEMENTED on the AMQP transport (`transport: Amqp`): the receive path acquires a broker-assigned session receiver (AcceptNextSession) and holds the session lock, so a group's in-flight messages stay pinned to one consumer and strict order is preserved. The session-id is carried in the v3 receipt handle so DeleteMessage / ChangeMessageVisibility route the settle back to the same live session link. The REST transport cannot express session-receive and therefore does NOT provide strict per-group ordering — it surfaces MessageGroupId on each message (so application-side de-grouping still works) but does not block concurrent delivery of the same group to different consumers (won't implement — inherent SB REST limitation). FIFO settle is connection-affine: an in-flight FIFO message cannot be settled from a different live connection while its session lock is held (SB session locks are connection-bound and non-serializable); on lock expiry the broker releases the session and the group becomes redeliverable, which matches SQS visibility-timeout semantics and enables scale-up rebalance. Proactive idle-TTL eviction of pooled session receivers is implemented (#262): a background sweeper closes session-receiver links with no receive/settle activity within a configurable idle window (default 5 min, AWS2AZURE_SB_SESSION_IDLE_SECONDS), returning the broker session for another consumer and freeing the AMQP link — resource hygiene, not a correctness gap.", "Diff: MessageGroupId is surfaced from BrokerProperties.SessionId; MessageDeduplicationId from BrokerProperties.MessageId. Both only appear in the response when the AttributeNames filter requests them (or 'All').", "Diff: FIFO session receive is not yet conformant on real Azure. Run 29472731381 timed out AcceptNextSession for one ready MessageGroupId; runs 29471929057 and 29471188679 failed on the same path with concurrent groups. The scenario remains explicitly skipped as optional FIFO coverage, while the standard non-FIFO lifecycle is covered separately.", "Diff: The standard-queue long-poll and receipt-handle path is validated against real Azure Service Bus through the message-lifecycle scenario.", "Diff: AMQP transport (Phase 2.5 slice 8b.4c, MessageAttributes round-trip in Phase 6 / #99): when a queue is configured with `transport: Amqp` (see ServiceBusCredentials.Queues), ReceiveMessage uses the in-process Service Bus AMQP 1.0 client via a shared connection pool. The receipt handle minted on the AMQP path is a distinct opaque format (version `2`, base64 of `{queueName, lockToken-GUID, lockedUntilUtc}`) carrying the SB lock-token directly rather than the REST messageId/lockToken pair. Long polling (WaitTimeSeconds) is honoured on the first receive; the polling-loop emulation that the REST path uses to batch up to 10 messages is replaced by a single `ReceiveBatchAsync` call against the cached AMQP link, which is more efficient. MessageAttributes (String/Number/Binary DataType round-trip) are now reconstructed from the `Aws2Azure-AttrTypes` application-property registry written by the AMQP send path; MD5OfMessageAttributes is computed via the shared `SqsMessageMd5.OfAttributes` helper so both transports produce the same hash. FIFO MessageGroupId is surfaced from `properties.group-id` (with the receiver's session-id as a fallback).", "Diff: Dead-letter attribution (AMQP path, Phase 2.5): when SB delivers a message from a `<queue>/$DeadLetterQueue` subqueue, the proxy surfaces three system attributes — `DeadLetterQueueSourceArn` (synthesised as `arn:aws:sqs:us-east-1:000000000000:<sourceQueueName>` from the SB `x-opt-deadletter-source` annotation; us-east-1 is a placeholder since the proxy doesn't model AWS regions, and the account id is `QueueUrlBuilder.PlaceholderAccountId`), `Aws2Azure-DeadLetterReason`, and `Aws2Azure-DeadLetterErrorDescription` (the latter two read from the dead-lettered message's application-properties, prefixed `Aws2Azure-` because SQS has no AWS-standard counterpart). All three respect the AttributeNames filter, are omitted entirely for non-DLQ messages, and are only emitted on the AMQP path (the REST path does not subscribe to DLQ subqueues yet).", "Diff: Emulator divergence (Phase 2.7 Slice 6): the Azure Service Bus emulator does NOT echo the broker-assigned session-id back in the receiver attach response's `com.microsoft:session-filter` when the client requests `sessionId=null` (broker-assigned), so FIFO end-to-end coverage against the emulator is impossible. Real Azure accepts the raw string/null filter shape, but current live runs wait until timeout before a session is assigned; no successful broker-assigned FIFO receive is claimed.", "Diff: Emulator divergence (Phase 2.7 Slice 7): the SB emulator's TTL-expiry sweeper does not reliably dead-letter messages once their `DefaultMessageTimeToLive` elapses and/or does not honour `ForwardDeadLetteredMessagesTo` on the resulting DLQ message within an integration-test budget — observed: forwarded message never arrives on the target queue within 45s. Real Service Bus's expiry pipeline runs every ~5s and performs the forward synchronously. DLQ-forward IT coverage lives in the real-Azure nightly smoke; the slice-7 emulator-backed DLQ test is gated with `Skip.If` documenting the divergence." }),
            new("RemovePermission", OperationStatus.Stub, new[] { "Azure: No native Service Bus equivalent — validates queue existence and returns success.", "Diff: No-op: returns 200 OK regardless of the Label. See AddPermission gap doc for the underlying rationale." }),
            new("SendMessage", OperationStatus.Implemented, new[] { "Azure: Azure Service Bus queue runtime REST API — POST /{queue}/messages?api-version=2021-05", "Diff: Per-queue transport selection (Phase 2.7 Slice 2): when the credential's serviceBus.transport (or per-queue override) is set to 'amqp', SendMessage is routed natively over AMQP via ServiceBusAmqpSender. The SQS-visible behaviour is identical to the REST path — same validation, same idempotency-key contract, same MD5 algorithm — only the wire to Service Bus differs. SendMessageBatch still goes over REST (Slice 3).", "Diff: MessageId is synthesised proxy-side (SB does not echo the message id on the runtime POST). For FIFO the MessageDeduplicationId is reused as the MessageId; otherwise a fresh Guid is minted.", "Diff: FIFO required-param validation (Slice 5): on a .fifo queue, MessageGroupId is required and the proxy returns MissingParameter when it is omitted. On standard queues, MessageGroupId and MessageDeduplicationId are rejected with InvalidParameterValue — matching SQS's per-attribute domain.", "Diff: SQS attribute data types (String/Number/Binary/'String.Custom') are flattened to SB application-property strings. The proxy emits an Aws2Azure-AttrTypes side-channel header so the receive path can faithfully reconstruct the original SQS shape — without it, all attributes would surface as String on receive.", "Diff: SQS's per-message cap is 1 MiB (1,048,576 bytes) — raised from 256 KiB in August 2025 — and includes the body plus every message attribute's name + data type + value bytes. The proxy enforces the same 1 MiB cap. The *effective* cap is also bounded by the backing Service Bus tier: SB Standard rejects anything over 256 KiB regardless, SB Premium honours up to 100 MiB. Per-queue MaximumMessageSize (1024..1048576) is recorded at CreateQueue time but not re-validated per send — SB itself rejects oversized payloads.", "Diff: Payloads larger than 1 MiB must use the AWS Extended Client Library, which stores the body in S3 and embeds a JSON pointer in the SQS message. That pointer flows through this proxy unchanged: the receive side returns the same pointer, and the embedded S3 reference resolves against the proxy's S3 → Blob translation, so end-to-end large-message support works as long as the client uses the Extended Client and the same proxy fronts both S3 and SQS.", "Diff: ScheduledEnqueueTimeUtc has millisecond resolution in SB; SQS DelaySeconds is integer seconds, so no loss occurs.", "Diff: The standard-queue send path is validated against real Azure Service Bus through the message-lifecycle scenario; FIFO session delivery remains optional coverage outside the standard profile." }),
            new("SendMessageBatch", OperationStatus.Implemented, new[] { "Azure: Azure Service Bus queue runtime REST API — POST /{queue}/messages with Content-Type: application/vnd.microsoft.servicebus.json", "Diff: Per-queue transport selection (Phase 2.7 Slice 3): when the credential's serviceBus.transport (or per-queue override) is set to 'amqp', SendMessageBatch dispatches each entry over a single AMQP sender link and aggregates the per-transfer dispositions. Unlike the REST path, this gives real per-entry partial-failure granularity — one rejected entry surfaces in Failed[] while the others remain Successful. Validation, FIFO interlock, idempotency-key minting, MD5 and response shape are otherwise identical to REST.", "Diff: SB's runtime batch send is atomic: the whole batch either succeeds or fails together (no AMQP-style per-message ack). The proxy preserves SQS's BatchResultErrorEntry shape: on a batch-level SB error every entry surfaces in Failed[] with the mapped SQS error code (SenderFault=true for client-side rejections, false for server-side). Genuine per-entry partial success (one bad entry mixed with good ones) is not available over SB REST.", "Diff: FIFO required-param validation (Slice 5): on a .fifo queue, every entry must carry a MessageGroupId; the proxy rejects the whole batch with MissingParameter on the first violating entry (validation runs before the SB call). On standard queues, MessageGroupId / MessageDeduplicationId on any entry yields InvalidParameterValue.", "Diff: Same attribute-flattening + Aws2Azure-AttrTypes side-channel as SendMessage. The 1 MiB aggregate cap is computed over body + attribute name/type/value bytes per the SQS quota docs (raised from 256 KiB in August 2025).", "Diff: Payloads larger than 1 MiB require the AWS Extended Client Library (S3-backed pointer); the same caveat as SendMessage applies — the pointer flows through unchanged and resolves against the proxy's S3 → Blob translation.", "Diff: Entry MessageId returned to the caller is proxy-synthesised (Guid, or MessageDeduplicationId for FIFO).", "Diff: Standard-queue batch send is validated against real Azure Service Bus with per-entry result evidence; FIFO session receive remains a separate unresolved gap." }),
            new("SetQueueAttributes", OperationStatus.Partial, new[] { "Azure: Azure Service Bus management REST API — PUT /{queue}?api-version=2021-05 with If-Match: * (whole-entity replace)", "Diff: Updates are not atomic across multiple concurrent SetQueueAttributes calls on the same queue: last write wins. If-Match: * is used (not the ETag we read) because SB does not surface the ETag in management responses on every emulator/version we tested. NFR phase may tighten this with an If-Match: <etag>.", "Diff: Several SQS-only attributes have no SB equivalent (Policy, KmsMasterKeyId, KmsDataKeyReusePeriodSeconds, SqsManagedSseEnabled, RedriveAllowPolicy). The proxy rejects them with InvalidAttributeName until Slice 5 (RedrivePolicy) and the security-encryption pass land.", "Diff: FIFO-only attributes (FifoQueue, FifoThroughputLimit, DeduplicationScope) cannot be flipped on an existing queue (SB rejects the change); the proxy returns InvalidAttributeName.", "Diff: Verified against in-process fakes; emulator-backed end-to-end validation is blocked because the Service Bus emulator does not expose the management REST API. Real-Azure validation pending." }),
            new("TagQueue", OperationStatus.Partial, new[] { "Azure: GET + PUT QueueDescription with aws2azure's base64 tag blob stored in UserMetadata.", "Diff: Tags are stored as an aws2azure-owned compact binary tag map, base64-encoded into Service Bus QueueDescription.UserMetadata. This preserves AWS tag keys and values exactly but consumes the queue's native UserMetadata field.", "Diff: If QueueDescription.UserMetadata is already non-empty and does not contain aws2azure's tag blob, TagQueue fails with InvalidParameterValue instead of overwriting operator-owned metadata.", "Diff: TagQueue uses the Service Bus management ETag from GET as the PUT If-Match value. A 412 Precondition Failed triggers a bounded refetch/remerge retry so concurrent queue property changes are not clobbered.", "Diff: Service Bus UserMetadata is limited to roughly 1024 characters in the legacy management schema, so valid SQS tag sets near the 50-tag / 128-key / 256-value maximum may be rejected when the serialized blob does not fit.", "Diff: Verified with in-process Service Bus management fakes. The Service Bus emulator does not validate or persist this management-plane UserMetadata path; real-Azure validation remains pending." }),
            new("UntagQueue", OperationStatus.Partial, new[] { "Azure: GET + PUT QueueDescription with aws2azure's base64 tag blob stored in UserMetadata.", "Diff: Tags are stored as an aws2azure-owned compact binary tag map, base64-encoded into Service Bus QueueDescription.UserMetadata. Removing the last tag clears that UserMetadata value.", "Diff: If QueueDescription.UserMetadata is already non-empty and does not contain aws2azure's tag blob, UntagQueue fails with InvalidParameterValue instead of overwriting operator-owned metadata.", "Diff: UntagQueue uses the Service Bus management ETag from GET as the PUT If-Match value. A 412 Precondition Failed triggers a bounded refetch/remerge retry so concurrent queue property changes are not clobbered.", "Diff: Service Bus UserMetadata is limited to roughly 1024 characters in the legacy management schema; aws2azure rejects updates that cannot fit the serialized tag map.", "Diff: Verified with in-process Service Bus management fakes. The Service Bus emulator does not validate or persist this management-plane UserMetadata path; real-Azure validation remains pending." }),
        });

